      http.use_ssl = uri.scheme == 'https'
      _headers = {}.dup
      _req = Net::HTTP::Get.new(uri.request_uri, _headers)
      response = http.request(_req)
      expect(response.code.to_i).to eq(422)
      _body = response.body && !response.body.empty? ? JSON.parse(response.body) : nil
      expect(_body).to eq({ 'detail' => '1 validation error in request', 'errors' => [{ 'input' => nil, 'loc' => ['headers', 'x-api-key'], 'msg' => 'Field required', 'type' => 'missing' }], 'status' => 422, 'title' => 'Request Validation Failed', 'type' => 'https://spikard.dev/errors/validation-error' })
      _body = JSON.parse(response.body)
      _errors = _body['errors'] || []
      expect(_errors.any? { |e| e['loc'] == ['headers', 'x-api-key'] && e['msg'].include?('Field required') }).to be true
    end
  end

